function auth(req,res,next){
 const token = req.headers.authorization;

 if(!token){
  return res.status(401).send('Unauthorized');
 }

 next();
}

const jwt = require('jsonwebtoken');

const decoded = jwt.verify(
 token,
 process.env.JWT_SECRET
);

req.user = decoded;

